const PATH_REGEX = /(?:[A-Za-z]:[\\/]|\\\\[^\s"'`)]+[\\/]|\/)[^\s"'`)]+/g;

// Path terminator class is [^\s"'`)]+ — terminates at whitespace, quote, or `)
// So a JSON-encoded error like:
//   `Failed to parse: {"file":"/home/user/secret.json","line":5}`
// — the path /home/user/secret.json is bordered by `"` which terminates the match.
// Match: `/home/user/secret.json` (TERMINATED at the trailing `"`).
// scrubMessage replaces with `<path>`.
// Result: `Failed to parse: {"file":"<path>","line":5}` — actually OK, terminator works.

// But: a JSON-stringified payload that doesn't quote the path?
// Example: `JSON.parse error at position 47 near {file: /home/user/secret.json}`
// (where the path appears UNQUOTED in some kernel-generated diagnostic)
// Match: `/home/user/secret.json}` (terminator is whitespace, } is included).
// Result: scrubbed but with trailing `}` swallowed — over-scrubs but no leak.

// REAL gap: paths in URL form. Example: `cluster://artifact//home/user/secret`
// Match begins at `//home/user/secret` — but wait, `//` is two slashes,
// the regex is `(?:[A-Za-z]:[\\/]|\\\\[^\s"'`)]+[\\/]|\/)[^\s"'`)]+` which matches
// a single `/` followed by non-terminator. So `cluster://...` -> match starts at `//home`
// and consumes through the path. Actually OK — over-scrubs the URI.

// THE GAP: relative paths that look like dotted dir names. `pending-content/abc123` (relative). Not matched.
// Also: bare process.cwd() patterns where cwd is not absolute (Node guarantees absolute, OK).
// And: Windows long-path prefix `\\?\C:\Users\...` — does the UNC arm match?
//   The UNC arm is `\\\\[^\s"'`)]+[\\/]` — matches `\\` then non-terminators then a slash.
//   For `\\?\C:\Users\foo`: starts with `\\`, then `?\C:\Users\foo` — terminator class allows `?`, `:`, etc.
//   So the UNC arm CONSUMES `\\?\C:` and looks for a trailing slash — `\` is fine.
//   Match: `\\?\C:\Users\foo`. Actually OK.

